# scripts/kp_pipeline/stage2_enrich.py
"""
Stage 2: 直联路径富化

补缺模块：对已识别 KP 名字但缺少直联（邮箱/电话）的线索，
通过网页搜索寻找直联路径。

已有能力复用：
- extract_public_contact_candidates.py 中的邮箱/电话提取逻辑
- workflow_checker.py 中的防重复和阈值控制
本模块只做"已知人名 → 搜直联"这一件事。
"""
import random
import re
import time
import xml.etree.ElementTree as ET
from datetime import datetime
from pathlib import Path
from urllib.parse import urlparse, quote_plus

import sys
sys.path.insert(0, str(Path(__file__).parent.parent))

from scrapling.fetchers import Fetcher
from workflow_checker import checker as workflow_checker

EMAIL_RE = re.compile(r"\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b", re.I)
PHONE_RE = re.compile(
    r"(?:"
    r"(?:\+?61[\s.-]*(?:0)?4\d{2}[\s.-]*\d{3}[\s.-]*\d{3})|"
    r"(?:04\d{2}[\s.-]*\d{3}[\s.-]*\d{3})|"
    r"(?:\(?0[2378]\)?[\s.-]*\d{4}[\s.-]*\d{4})|"
    r"(?:(?:1300|1800)[\s.-]*\d{3}[\s.-]*\d{3})"
    r")"
)

EMAIL_SKIP = {"noreply", "no-reply", "careers", "jobs", "hr", "privacy", "media", "marketing"}
EMAIL_DEPARTMENT = {"sales", "procurement", "accounts", "events", "functions", "enquiries", "hello", "info", "admin"}
LINKEDIN_RE = re.compile(r"https?://(?:www\.)?linkedin\.com/in/[\w\-]+/?", re.I)


def classify_email(email):
    """将邮箱分类为个人、部门或公司邮箱。"""
    if not email:
        return "unknown"
    local = email.split("@")[0].lower()
    # 个人邮箱优先（含点或下划线）
    if "." in local or "_" in local:
        parts = local.replace("_", ".").split(".")
        if len(parts) >= 2 and all(p.isalpha() for p in parts):
            return "person_email"
    # 公司通用邮箱（先于部门判断）
    if local in ("info", "admin", "contact", "hello", "enquiries"):
        return "company_email"
    # 部门邮箱
    if any(local.startswith(p) for p in EMAIL_DEPARTMENT):
        return "department_email"
    return "possible_person_email"


def classify_contact_directness(email, phone, linkedin=""):
    """分类联系路径的直联程度。"""
    has_email = bool(email and email.strip())
    has_phone = bool(phone and phone.strip())
    has_linkedin = bool(linkedin and linkedin.strip())

    if has_email:
        email_type = classify_email(email)
        if email_type == "person_email":
            return "direct", "High"
        if email_type == "possible_person_email":
            return "direct", "Medium"

    if has_phone and phone.strip().startswith("04"):
        return "direct", "High"

    if has_linkedin:
        return "linkedin_only", "Medium"

    if has_email or has_phone:
        return "company_route", "Medium"

    return "name_only", "Low"


def is_noisy_domain(url, blocklist):
    """检查 URL 是否在噪声域名黑名单中。"""
    if not url:
        return False
    try:
        parsed = urlparse(url if "://" in url else f"https://{url}")
        domain = parsed.netloc.lower()
        if domain.startswith("www."):
            domain = domain[4:]
        return any(noisy in domain for noisy in blocklist)
    except Exception:
        return False


def fetch_page_text(url, timeout=15):
    """抓取页面并提取文本。"""
    try:
        page = Fetcher.get(url, timeout=timeout, retries=1)
        status = getattr(page, "status", 0)
        if not str(status).startswith("2"):
            return None, f"HTTP {status}"
        text = page.get_all_text(separator=" ") if hasattr(page, "get_all_text") else page.text
        return text, None
    except Exception as e:
        return None, f"{type(e).__name__}: {e}"


def _get_page_xml(page):
    """从 Scrapling response 提取 XML 文本（兼容 text/body）。"""
    body = getattr(page, "body", None)
    if body:
        if isinstance(body, bytes):
            return body.decode("utf-8", errors="replace")
        return str(body)
    text = getattr(page, "text", None)
    return text or ""


def fetch_sitemap_urls(domain, timeout=10):
    """从 sitemap.xml 提取页面 URL 列表。"""
    sitemap_urls = [
        f"https://{domain}/sitemap.xml",
        f"https://{domain}/sitemap_index.xml",
        f"https://{domain}/sitemap-index.xml",
        f"https://www.{domain}/sitemap.xml",
    ]

    for sitemap_url in sitemap_urls:
        try:
            page = Fetcher.get(sitemap_url, timeout=timeout, retries=1)
            status = getattr(page, "status", 0)
            if not str(status).startswith("2"):
                continue
            xml_text = _get_page_xml(page)
            if not xml_text or "<" not in xml_text:
                continue

            # 解析 XML
            try:
                root = ET.fromstring(xml_text)
            except ET.ParseError:
                continue

            # 处理 sitemap index（嵌套 sitemap）
            ns = {"sm": "http://www.sitemaps.org/schemas/sitemap/0.9"}
            sitemap_tags = root.findall(".//sm:sitemap/sm:loc", ns)
            if sitemap_tags:
                all_urls = []
                for loc in sitemap_tags[:3]:  # 最多读 3 个子 sitemap
                    sub_url = loc.text.strip() if loc.text else ""
                    if sub_url:
                        sub_page = Fetcher.get(sub_url, timeout=timeout, retries=1)
                        if str(getattr(sub_page, "status", 0)).startswith("2"):
                            sub_xml = _get_page_xml(sub_page)
                            if sub_xml:
                                try:
                                    sub_root = ET.fromstring(sub_xml)
                                    for u in sub_root.findall(".//sm:loc", ns):
                                        if u.text:
                                            all_urls.append(u.text.strip())
                                except ET.ParseError:
                                    pass
                return all_urls

            # 直接 sitemap
            urls = []
            for loc in root.findall(".//sm:loc", ns):
                if loc.text:
                    urls.append(loc.text.strip())
            return urls

        except Exception:
            continue
    return []


def filter_team_pages(sitemap_urls):
    """从 sitemap URL 列表中筛选团队/联系相关页面。"""
    team_keywords = [
        "team", "about", "people", "staff", "leadership", "management",
        "our-team", "meet-the-team", "contact", "who-we-are",
        "directors", "founders", "executives",
    ]
    matched = []
    for url in sitemap_urls:
        url_lower = url.lower()
        path = urlparse(url_lower).path
        if any(kw in path for kw in team_keywords):
            matched.append(url)
    return matched


def extract_emails_from_text(text):
    """从文本提取并过滤邮箱。"""
    if not text:
        return []
    raw = set(EMAIL_RE.findall(text))
    return [e.lower() for e in raw if not any(e.lower().split("@")[0].startswith(s) for s in EMAIL_SKIP)]


def extract_phones_from_text(text):
    """从文本提取澳大利亚电话号码。"""
    if not text:
        return []
    return list(set(PHONE_RE.findall(text)))


def find_person_email(emails, kp_name):
    """从邮箱列表中找到匹配 KP 名字的邮箱。"""
    if not emails or not kp_name:
        return ""
    name_parts = kp_name.lower().split()
    for email in emails:
        local = email.split("@")[0].lower()
        if all(part in local for part in name_parts if len(part) > 2):
            return email
    return ""


def extract_linkedin_urls(text):
    """从文本提取 LinkedIn 个人主页 URL。"""
    if not text:
        return []
    return list(set(LINKEDIN_RE.findall(text)))


def human_delay(base=2.0, jitter=1.5):
    """随机延迟，模拟人类浏览节奏。"""
    time.sleep(base + random.uniform(0, jitter))


def build_google_dork_queries(kp_name, company_name, domain):
    """构建 Google dork 查询列表（复用 generate_kp_search_tasks.py 的模式）。"""
    queries = []
    if domain:
        queries.append(f'site:{domain} "{kp_name}"')
    queries.append(f'"{kp_name}" "{company_name}" email OR phone OR contact')
    queries.append(f'"{kp_name}" "{company_name}" director OR operations OR procurement')
    # LinkedIn 搜索
    queries.append(f'site:linkedin.com/in "{kp_name}" "{company_name}"')
    return queries


def search_google(query, max_results=5):
    """执行 Google 搜索，返回结果页面 URL 列表。"""
    url = f"https://www.google.com/search?q={quote_plus(query)}&num={max_results}"
    try:
        page = Fetcher.get(url, timeout=15, retries=1)
        status = getattr(page, "status", 0)
        if not str(status).startswith("2"):
            return []

        # 提取搜索结果链接
        result_urls = []
        if hasattr(page, "css"):
            for link in page.css("a"):
                href = link.attrib.get("href", "")
                if href and "/url?q=" in href:
                    # 提取真实 URL
                    real_url = href.split("/url?q=")[1].split("&")[0]
                    if real_url.startswith("http"):
                        parsed = urlparse(real_url)
                        domain = parsed.netloc.lower()
                        # 排除 Google 自己的链接和噪声域名
                        if "google.com" not in domain and "googleapis.com" not in domain:
                            result_urls.append(real_url)
                            if len(result_urls) >= max_results:
                                break
        return result_urls
    except Exception:
        return []


def extract_all_contacts_from_url(url, company_name, existing_names=None):
    """从页面提取所有可识别的联系人（同公司多人）。"""
    text, error = fetch_page_text(url)
    if not text:
        return []

    emails = extract_emails_from_text(text)
    phones = extract_phones_from_text(text)
    linkedin_urls = extract_linkedin_urls(text)
    existing_names = set(n.lower() for n in (existing_names or []))

    contacts = []

    # 从个人邮箱推断联系人
    for email in emails:
        local = email.split("@")[0].lower()
        # 个人邮箱（含点或下划线）
        if "." in local or "_" in local:
            parts = local.replace("_", ".").split(".")
            if len(parts) >= 2 and all(p.isalpha() and len(p) > 1 for p in parts):
                name = " ".join(p.capitalize() for p in parts)
                if name.lower() not in existing_names:
                    contacts.append({
                        "name": name,
                        "company_name": company_name,
                        "source_url": url,
                        "best_email": email,
                        "best_phone": "",
                        "best_linkedin": "",
                        "person_email_found": True,
                        "inferred_from": "email_pattern",
                    })
                    existing_names.add(name.lower())

    # 从 LinkedIn URL 推断联系人
    for lu in linkedin_urls:
        # linkedin.com/in/firstname-lastname
        slug = lu.rstrip("/").split("/")[-1].lower()
        parts = slug.split("-")
        if len(parts) >= 2 and all(p.isalpha() and len(p) > 1 for p in parts):
            name = " ".join(p.capitalize() for p in parts if p not in ("au", "com", "linkedin"))
            if name and name.lower() not in existing_names:
                contacts.append({
                    "name": name,
                    "company_name": company_name,
                    "source_url": url,
                    "best_email": "",
                    "best_phone": "",
                    "best_linkedin": lu,
                    "person_email_found": False,
                    "inferred_from": "linkedin_url",
                })
                existing_names.add(name.lower())

    return contacts


def enrich_kp_from_url(url, kp_name, company_name):
    """从指定 URL 提取 KP 的直联信息。"""
    text, error = fetch_page_text(url)
    if not text:
        return None

    # 检查 KP 名字是否出现在页面上
    if kp_name.lower() not in text.lower():
        return None

    emails = extract_emails_from_text(text)
    phones = extract_phones_from_text(text)
    linkedin_urls = extract_linkedin_urls(text)
    person_email = find_person_email(emails, kp_name)

    # 匹配 KP 名字的 LinkedIn（名字出现在 URL 附近）
    best_linkedin = ""
    if linkedin_urls:
        # 优先选择包含 KP 名字部分的 LinkedIn URL
        name_parts = [p.lower() for p in kp_name.split() if len(p) > 2]
        for lu in linkedin_urls:
            if any(part in lu.lower() for part in name_parts):
                best_linkedin = lu
                break
        if not best_linkedin:
            best_linkedin = linkedin_urls[0]

    return {
        "name": kp_name,
        "company_name": company_name,
        "source_url": url,
        "emails": emails,
        "phones": phones,
        "linkedin_urls": linkedin_urls,
        "best_email": person_email or (emails[0] if emails else ""),
        "best_phone": phones[0] if phones else "",
        "best_linkedin": best_linkedin,
        "person_email_found": bool(person_email),
    }


def enrich_lead_kp(lead, config):
    """对单条线索的已知 KP 进行直联富化。"""
    stage_config = config.get("stages", {}).get("stage2_enrich", {})
    blocklist = stage_config.get("noisy_domains_blocklist", [])
    delay = stage_config.get("delay_between_requests_seconds", 2.0)

    lead_id = lead.get("lead_id", "")
    company_name = lead.get("company_name", "")
    kp_name = lead.get("key_contact_name", "").strip()
    website = (lead.get("website") or "").strip()

    if not kp_name or not website:
        return None, "missing_kp_or_website"

    # 解析域名
    try:
        parsed = urlparse(website if "://" in website else f"https://{website}")
        domain = parsed.netloc.lower()
        if domain.startswith("www."):
            domain = domain[4:]
    except Exception:
        return None, "invalid_url"

    if is_noisy_domain(website, blocklist):
        return None, "noisy_domain"

    # 检查是否已有直联
    existing_email = lead.get("key_contact_email", "").strip()
    existing_phone = lead.get("key_contact_phone", "").strip()
    if existing_email or existing_phone:
        return None, "already_has_direct_contact"

    # 先从已有官网联系页/团队页尝试富化
    candidate_urls = []

    # 已知的联系页面
    contact_page = lead.get("company_contact_page", "").strip()
    contact_form = lead.get("company_contact_form_url", "").strip()
    if contact_page:
        candidate_urls.append(contact_page)
    if contact_form and contact_form != contact_page:
        candidate_urls.append(contact_form)

    # 从 sitemap 获取团队/联系页面
    sitemap_urls = fetch_sitemap_urls(domain)
    if sitemap_urls:
        team_pages = filter_team_pages(sitemap_urls)
        candidate_urls.extend(team_pages)

    # sitemap 没找到时，回退到猜路径
    if not any(kw in url.lower() for url in candidate_urls
               for kw in ["team", "about", "people", "leadership", "our-team", "contact"]):
        for path in ["/team", "/about", "/people", "/leadership", "/our-team"]:
            candidate_urls.append(f"https://{domain}{path}")

    results = []
    errors = []

    # 第一阶段：从已知官网页面提取
    for url in candidate_urls:
        if is_noisy_domain(url, blocklist):
            continue

        result = enrich_kp_from_url(url, kp_name, company_name)
        if result:
            directness, confidence = classify_contact_directness(result["best_email"], result["best_phone"], result.get("best_linkedin", ""))
            result["directness"] = directness
            result["confidence"] = confidence
            result["lead_id"] = lead_id
            result["search_phase"] = "direct_page"
            results.append(result)

            # 如果找到直联，不需要继续搜索
            if directness == "direct":
                break

        human_delay(delay)

    # 第二阶段：Google dork 搜索（仅当第一阶段未找到直联时）
    has_direct = any(r.get("directness") == "direct" for r in results)
    if not has_direct:
        dork_queries = build_google_dork_queries(kp_name, company_name, domain)
        for query in dork_queries:
            search_urls = search_google(query, max_results=3)
            for url in search_urls:
                if is_noisy_domain(url, blocklist):
                    continue

                result = enrich_kp_from_url(url, kp_name, company_name)
                if result:
                    directness, confidence = classify_contact_directness(result["best_email"], result["best_phone"], result.get("best_linkedin", ""))
                    result["directness"] = directness
                    result["confidence"] = confidence
                    result["lead_id"] = lead_id
                    result["search_phase"] = "google_dork"
                    result["search_query"] = query
                    results.append(result)

                    if directness == "direct":
                        break

                human_delay(delay)

            if any(r.get("directness") == "direct" for r in results):
                break

    if not results:
        return None, "no_contact_found"

    # 返回最佳结果（优先直联 > LinkedIn > 公司路径）
    def result_rank(r):
        d = r.get("directness", "")
        return (
            d == "direct",
            r.get("person_email_found", False),
            bool(r.get("best_linkedin")),
            d == "linkedin_only",
            d == "company_route",
            len(r.get("emails", [])),
        )

    best = max(results, key=result_rank)

    # 第三阶段：从团队页面提取同公司其他联系人
    team_pages = [url for url in candidate_urls
                  if any(kw in url.lower() for kw in ["team", "about", "people", "leadership", "our-team"])]
    additional = []
    known_names = {kp_name.lower()}
    if best.get("name"):
        known_names.add(best["name"].lower())

    for url in team_pages:
        if is_noisy_domain(url, blocklist):
            continue
        others = extract_all_contacts_from_url(url, company_name, existing_names=known_names)
        for o in others:
            o["lead_id"] = lead_id
            o["search_phase"] = "team_page"
            dc, cf = classify_contact_directness(o.get("best_email", ""), o.get("best_phone", ""), o.get("best_linkedin", ""))
            o["directness"] = dc
            o["confidence"] = cf
            additional.append(o)
            known_names.add(o["name"].lower())
        if additional:
            break  # 找到一个团队页就够了

    best["additional_contacts"] = additional
    return best, "enriched"


def run_stage2(leads_with_kp, config):
    """对已有 KP 名字但缺直联的线索列表运行 Stage 2。"""
    from .metrics import log_run_metrics

    stage_config = config.get("stages", {}).get("stage2_enrich", {})
    if not stage_config.get("enabled", True):
        return [], {"skipped": True}

    run_id = f"S2-{datetime.now().strftime('%Y%m%d-%H%M%S')}"
    workflow_checker.load_existing_data()

    enriched = []
    processed = 0
    direct_found = 0
    additional_count = 0
    skipped = 0

    for lead in leads_with_kp:
        processed += 1
        result, status = enrich_lead_kp(lead, config)

        if result:
            enriched.append(result)
            if result.get("directness") == "direct":
                direct_found += 1
            # 将同公司其他联系人也加入结果
            extras = result.get("additional_contacts", [])
            additional_count += len(extras)
            for extra in extras:
                enriched.append(extra)
                if extra.get("directness") == "direct":
                    direct_found += 1
        elif status in ("already_has_direct_contact", "missing_kp_or_website", "noisy_domain"):
            skipped += 1

    metrics = {
        "candidates_processed": processed,
        "enriched": len(enriched),
        "direct_contacts_found": direct_found,
        "additional_contacts": additional_count,
        "skipped": skipped,
        "direct_contact_rate": round(direct_found / max(processed - skipped, 1), 3),
    }
    log_run_metrics(run_id, "stage2_enrich", metrics)

    return enriched, metrics

# scripts/kp_pipeline/stage3_validate.py
"""
Stage 3: 验证与人工审核门控

对 KP 候选人进行验证，自动批准/拒绝/排队人工审核。
"""
from datetime import datetime
from .metrics import log_run_metrics


FALSE_POSITIVE_NAMES = {
    "contact", "dining", "menu", "home", "about", "team", "leadership",
    "management", "staff", "people", "careers", "our team", "the team",
    "our people", "meet the", "read more", "learn more", "find out",
    "get in", "click here", "sign up", "subscribe", "privacy", "terms",
}


def validate_candidate(candidate, rules):
    """根据规则验证单个 KP 候选人。"""
    issues = []
    name = (candidate.get("name") or "").strip()
    source_url = (candidate.get("source_url") or "").strip()

    # 检查误报
    reject_list = rules.get("reject_common_false_positives", [])
    reject_set = {fp.lower() for fp in reject_list} | FALSE_POSITIVE_NAMES
    if name.lower() in reject_set:
        issues.append(f"误报: '{name}'")

    # 检查名字长度
    min_len = rules.get("min_name_length", 4)
    max_len = rules.get("max_name_length", 50)
    if len(name) < min_len:
        issues.append(f"名字太短: '{name}'")
    if len(name) > max_len:
        issues.append(f"名字太长: '{name}'")

    # 检查来源
    if rules.get("require_source_link", True) and not source_url:
        issues.append("缺少来源链接")

    return {"valid": len(issues) == 0, "issues": issues}


def classify_auto_decision(score, config, is_valid):
    """将候选人分类为 auto_approve / auto_reject / human_review。"""
    if not is_valid:
        return "auto_reject"
    if score >= config.get("auto_approve_threshold", 85):
        return "auto_approve"
    if score < config.get("auto_reject_threshold", 30):
        return "auto_reject"
    return "human_review"


def compute_score(candidate):
    """为候选人计算综合分数。"""
    score = 50  # 基础分

    email = (candidate.get("best_email") or "").strip()
    phone = (candidate.get("best_phone") or "").strip()
    linkedin = (candidate.get("linkedin_url") or candidate.get("best_linkedin") or "").strip()
    directness = candidate.get("directness", "")
    confidence = candidate.get("confidence", "")

    # 无任何联系方式 → 大幅扣分（仅名字无价值）
    has_any_contact = bool(email or phone or linkedin)
    if not has_any_contact:
        return 20  # 低于 30 自动拒绝

    # 公司通用邮箱扣分
    if email:
        local = email.split("@")[0].lower()
        company_locals = {"info", "admin", "contact", "hello", "enquiries", "enquiry", "sales", "accounts", "hr", "marketing", "media"}
        if local in company_locals:
            score -= 10  # 公司邮箱降低价值

    # 直联程度加分
    if directness == "direct" and confidence == "High":
        score += 35
    elif directness == "direct" and confidence == "Medium":
        score += 25
    elif directness == "linkedin_only":
        score += 15  # LinkedIn 有价值但不如直联
    elif directness == "company_route":
        score += 5  # 公司路径降低加分

    # 个人邮箱加分
    if candidate.get("person_email_found"):
        score += 15

    # LinkedIn 加分
    if linkedin:
        score += 10

    # 角色上下文加分
    role = (candidate.get("role_context") or candidate.get("candidate_title") or "").lower()
    if any(r in role for r in ["managing director", "ceo", "founder", "owner", "director"]):
        score += 15
    elif any(r in role for r in ["operations", "procurement", "general manager"]):
        score += 10

    return max(min(score, 100), 0)


def run_stage3(candidates, config):
    """对候选人列表运行 Stage 3 验证。"""
    stage_config = config.get("stages", {}).get("stage3_validate", {})
    if not stage_config.get("enabled", True):
        return {"skipped": True}

    run_id = f"S3-{datetime.now().strftime('%Y%m%d-%H%M%S')}"
    rules = stage_config.get("validation_rules", {})

    auto_approved = []
    auto_rejected = []
    human_review = []

    for candidate in candidates:
        score = compute_score(candidate)
        candidate["score"] = score

        validation = validate_candidate(candidate, rules)
        decision = classify_auto_decision(score, stage_config, validation["valid"])
        candidate["decision"] = decision
        candidate["validation_issues"] = validation["issues"]

        if decision == "auto_approve":
            auto_approved.append(candidate)
        elif decision == "auto_reject":
            auto_rejected.append(candidate)
        else:
            human_review.append(candidate)

    metrics = {
        "total_candidates": len(candidates),
        "auto_approved": len(auto_approved),
        "auto_rejected": len(auto_rejected),
        "human_review": len(human_review),
        "auto_approve_rate": round(len(auto_approved) / max(len(candidates), 1), 3),
    }
    log_run_metrics(run_id, "stage3_validate", metrics)

    return {
        "auto_approved": auto_approved,
        "auto_rejected": auto_rejected,
        "human_review": human_review,
        "metrics": metrics,
    }

import json
import os
import re
import sys
from datetime import datetime
from pathlib import Path


ROOT = Path(__file__).resolve().parents[2]
LOG_DIR = ROOT / ".codex" / "logs"


def read_event():
    try:
        raw = os.sys.stdin.read()
    except Exception:
        raw = ""

    if not raw.strip():
        return {}

    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return {"raw_input": raw}


def append_jsonl(name, payload):
    """
    Write local runtime logs only.
    Never print these logs to stdout, because Codex hook stdout has a strict schema.
    """
    try:
        LOG_DIR.mkdir(parents=True, exist_ok=True)
        payload = dict(payload)
        payload.setdefault("ts", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))

        with (LOG_DIR / name).open("a", encoding="utf-8") as fh:
            fh.write(json.dumps(payload, ensure_ascii=False) + "\n")
    except Exception:
        # Hook logging should not break normal Codex work.
        pass


def event_name(event):
    return str(event.get("hook_event_name") or event.get("event") or "")


def flatten_text(value):
    parts = []

    if isinstance(value, str):
        parts.append(value)
    elif isinstance(value, dict):
        for item in value.values():
            parts.append(flatten_text(item))
    elif isinstance(value, list):
        for item in value:
            parts.append(flatten_text(item))

    return "\n".join(part for part in parts if part)


def changed_paths(event):
    text = flatten_text(event)
    paths = set()

    for pattern in (
        r"(?P<path>(?:data|docs|scripts|dashboard|\.codex|reports|README\.md|AGENTS\.md|requirements\.txt)[^\s\"']*)",
        r"\*\*\* (?:Add|Update|Delete) File: (?P<patch_path>[^\r\n]+)",
    ):
        for match in re.finditer(pattern, text):
            path = match.groupdict().get("path") or match.groupdict().get("patch_path")
            if path:
                paths.add(path.replace("\\", "/").strip())

    return sorted(paths)


def allow(message=None, warnings=None, log_name=None, extra=None):
    """
    Allow the hook to pass.

    Important:
    - Do not print JSON to stdout.
    - Codex treats stdout as structured hook output for some events.
    - Invalid stdout JSON causes hook returned invalid ... JSON output.
    """
    payload = {
        "decision": "allow",
        "message": message,
        "warnings": warnings or [],
    }

    if extra:
        payload.update(extra)

    if log_name:
        append_jsonl(log_name, payload)

    sys.exit(0)


def warn_only(message, warnings=None, log_name=None, extra=None):
    """
    Advisory warning only. Do not block Codex.
    Write warning to stderr so the user can see it, but exit 0.
    """
    warnings = warnings or []

    if message:
        print(message, file=sys.stderr)

    for warning in warnings:
        print(f"Warning: {warning}", file=sys.stderr)

    payload = {
        "decision": "warn",
        "message": message,
        "warnings": warnings,
    }

    if extra:
        payload.update(extra)

    if log_name:
        append_jsonl(log_name, payload)

    sys.exit(0)


def deny(reason, log_name=None, extra=None):
    """
    Block the hook.

    Codex-safe behavior:
    - Print reason to stderr.
    - Exit with code 2.
    - Do not print Claude-style JSON to stdout.
    """
    print(reason, file=sys.stderr)

    payload = {
        "decision": "deny",
        "reason": reason,
    }

    if extra:
        payload.update(extra)

    if log_name:
        append_jsonl(log_name, payload)

    sys.exit(2)


# Backward-compatible aliases.
# These keep old hook scripts easier to update, but they no longer return JSON payloads.
def ok(message=None, warnings=None):
    allow(message=message, warnings=warnings)


def warn(message, warnings):
    warn_only(message=message, warnings=warnings)

import subprocess
import sys

from hook_utils import (
    ROOT,
    append_jsonl,
    changed_paths,
    event_name,
    flatten_text,
    read_event,
)


PY_SCRIPTS = {
    "scripts/extraction/build_form_kp_candidate_queue.py",
    "scripts/extraction/extract_public_contact_candidates.py",
    "scripts/extraction/generate_kp_form_queries.py",
    "scripts/utils/check_capability_inventory.py",
}


def compile_changed_scripts(paths):
    scripts = sorted(
        path
        for path in paths
        if path in PY_SCRIPTS or (path.startswith("scripts/") and path.endswith(".py"))
    )

    if not scripts:
        return []

    cmd = [sys.executable, "-m", "py_compile", *scripts]
    result = subprocess.run(cmd, cwd=ROOT, text=True, capture_output=True)

    if result.returncode == 0:
        append_jsonl(
            "post_tool.jsonl",
            {
                "check": "py_compile",
                "scripts": scripts,
                "returncode": result.returncode,
                "status": "ok",
            },
        )
        return []

    detail = result.stderr.strip() or result.stdout.strip() or "unknown compile error"
    append_jsonl(
        "post_tool.jsonl",
        {
            "check": "py_compile",
            "scripts": scripts,
            "returncode": result.returncode,
            "status": "failed",
            "detail": detail,
        },
    )
    short_detail = detail[:500]
    return [f"Python compile failed for {', '.join(scripts)}: {short_detail}"]


def current_progress_warnings(paths, text):
    if "docs/current-progress.md" not in paths:
        return []

    lowered = text.lower()
    checkpoint_terms = (
        "handoff",
        "checkpoint",
        "context",
        "major",
        "milestone",
        "resume",
        "account",
        "账号",
        "切换",
        "上下文",
        "检查点",
    )

    if any(term in lowered for term in checkpoint_terms):
        return []

    return [
        "`docs/current-progress.md` should only change for handoff/checkpoint/context-risk/major milestone needs."
    ]


def capability_warnings(paths):
    touched_tooling = any(
        path in paths
        for path in ("requirements.txt", "README.md", "scripts/utils/check_capability_inventory.py")
    ) or any(path.startswith("scripts/") and path.endswith(".py") for path in paths)

    if not touched_tooling:
        return []

    required = {
        "README.md",
        "requirements.txt",
        "scripts/utils/check_capability_inventory.py",
        "docs/request-solution-log.md",
    }

    missing = sorted(required - set(paths))

    if missing:
        return [
            "Tool/capability changes should keep inventory aligned; consider whether these also need updates: "
            + ", ".join(missing)
        ]

    return []


def utf8_warnings(paths):
    warnings = []

    chinese_docs = [
        path
        for path in paths
        if path.endswith(".md") and (path.startswith("docs/") or path in ("README.md", "AGENTS.md"))
    ]

    for rel in chinese_docs:
        file_path = ROOT / rel

        if not file_path.exists():
            continue

        try:
            text = file_path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            warnings.append(f"{rel} is not valid UTF-8.")
            continue

        if "�" in text:
            warnings.append(f"{rel} contains replacement characters; check for mojibake.")

    return warnings


def request_log_warning(paths):
    important = any(
        path.startswith(prefix)
        for path in paths
        for prefix in ("docs/", "data/", "scripts/", ".codex/")
    ) or any(path in ("README.md", "AGENTS.md", "requirements.txt") for path in paths)

    if important and "docs/request-solution-log.md" not in paths:
        return [
            "This task changed project files; check whether `docs/request-solution-log.md` needs an entry."
        ]

    return []


def main():
    event = read_event()
    paths = changed_paths(event)
    text = flatten_text(event)

    warnings = []
    warnings.extend(current_progress_warnings(paths, text))
    warnings.extend(capability_warnings(paths))
    warnings.extend(utf8_warnings(paths))
    warnings.extend(request_log_warning(paths))
    warnings.extend(compile_changed_scripts(paths))

    append_jsonl(
        "post_tool.jsonl",
        {
            "event": event_name(event),
            "paths": paths,
            "warnings": warnings,
        },
    )

    # Codex-safe output:
    # - Do not print Claude-style JSON to stdout.
    # - Warnings go to stderr only.
    # - PostToolUse should not block normal work.
    for warning in warnings:
        print(f"PostToolUse warning: {warning}", file=sys.stderr)

    sys.exit(0)


if __name__ == "__main__":
    main()

